PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?races
WHERE {
  ?season wdt:P1344 wd:Q9673;
          wdt:P155 wd:Q193338;
          wdt:P580 ?start;
          wdt:P1113 ?races.
  BIND(YEAR(?start) AS ?year)
  FILTER (?year > 2015)
}
ORDER BY ASC(?races)
LIMIT 1

